module bug_sub(
    input wire clk,
    input wire buggy_a,
    output wire x
); 
reg [24:0] count; 
always @(posedge clk)
    if (buggy_a)
        count <= count + 1'b1; 
    
assign x = count[24]; 
endmodule

module bug_top(
    input wire clk,
    input wire a, 
    input wire b,
    output wire x
);`
    wire undriven_wire;
    // assign undriven_wire = 1'b0; 
    bug_sub this_sub (
        .clk(clk),
        .buggy_a(a | undriven_wire),
        .x(x)
    );

endmodule
